var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>로터스 대균열</color>\\n고심도 좌표 <color=#ffd34c>그림자 전당</color>","JPN":"<color=#ffd34c>ロータス大亀裂</color>\\n高深度座標、<color=#ffd34c>影の殿堂</color>","ENG":"<color=#ffd34c>Lotus Grand Dimension Crevice</color>\\nHyperdepth Coordinates, <color=#ffd34c>Shadow Palace</color>","TWN":"<color=#ffd34c>洛德斯大峽谷</color>\\n高深度座標 <color=#ffd34c>暗影殿堂</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>마왕 강림 및 현실 차원계면 붕괴까지… 앞으로 13분.</color>","JPN":"<color=#ffd34c>魔王降臨および現実の次元界面の崩壊まで……残りおよそ13分。</color>","ENG":"<color=#ffd34c>Demon Lord's descent and the collapse of Normalside's dimension surface in... approximately 13 minutes.</color>","TWN":"<color=#ffd34c>距離魔王降臨和現實次元邊界崩潰……剩餘13分鐘。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으그그극…!","JPN":"うぐぐ……！","ENG":"Errgh...!","TWN":"咳……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"팀을… 해치게 놔두진 않아요.","JPN":"チームへの……攻撃はさせません。","ENG":"I... won't let you hurt my team.","TWN":"我不會讓你……傷害同伴。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 망원렌즈를 고작 방패 따위로 삼다니.","JPN":"あの望遠レンズを盾にするとは。","ENG":"Such a waste, using the Zoom Lens as a shield.","TWN":"竟然將那個望遠鏡頭當作盾牌使用。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 그런 도구를 가지고도 성장이 정말 더디네요.","JPN":"あなたはそんな道具も持っているくせに、成長が遅いですね。","ENG":"You seem to show slow growth even with a tool like that.","TWN":"即使有了這些工具，你的成長依然非常緩慢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으갸앗…!","JPN":"うぎゃぁ……！","ENG":"Aaagh...!","TWN":"呀啊……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"꼬맹이!","JPN":"おこちゃま！","ENG":"Kid!","TWN":"小鬼！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"큭?! 제길! 내 총이…!","JPN":"くっ！？　くそ！　私の銃が……！","ENG":"Kgh?! Dammit! My gun...!","TWN":"呃？！該死！我的槍……！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐아앗? 몸이 멋대로 떠오른다?!","JPN":"ふええ？　体が勝手に浮きましたよ！？","ENG":"Huaaaah? I'm floating?!","TWN":"啊啊啊？身體浮起來了？！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"어떻게 한 거지?! 사람을 무슨 자석처럼…!","JPN":"何をしたんだ！？　人を磁石のように……！","ENG":"How's she doing that?! She's controlling people like they're magnets...!","TWN":"這是怎麼做到的？把人像磁鐵一般……！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"루이즈 로랑생, 당신이 가진 아티팩트의 제대로 된 사용법을 지금부터 가르쳐드리죠.","JPN":"ルイーズ・ローランセン、あなたが持っているアーティファクトの本当の使い方を今からご教授しましょう。","ENG":"Louisé Laurencin, I shall teach you the proper way to use your Artifact.","TWN":"露易絲·羅蘭桑，我來告訴你吧，你的人造神器的正確使用方法。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……!"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_HIT_SLASH_BIG"},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아야야… 또 꼬리뼈 부딪혔어어.","JPN":"いたた……また尾骨がぶつかった。","ENG":"Oww... I fell on my tailbone again.","TWN":"唔呃呃……又撞到尾骨了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"풀려났다고? 어떻게 된 거지?","JPN":"解放された？　どういうことだ？","ENG":"She's free? But how?","TWN":"鬆開了？怎麼回事？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저 갑옷은…?","JPN":"あの鎧は……？","ENG":"That armor...","TWN":"那副盔甲是……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이곳의 인간들에게 더는 간섭하지 마라, 이방인이여.","JPN":"ここの人間にこれ以上干渉するな、異邦人。","ENG":"Do not interfere with the humans of this world anymore, outsider.","TWN":"不要再干涉這個世界的人類了，異鄉人。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어떻게 돌아온 거죠?","JPN":"どうやって戻ったのですか？","ENG":"How were you able to return?","TWN":"你是怎麼回來的？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 열쇠의 기능을 다하고 퇴장하는 것이 본래의 역할이었을 텐데요.","JPN":"あなたは鍵としての機能を果たして退場するのが本来の役割のはずですが。","ENG":"Your original role was to do your part as the key and exit the stage.","TWN":"你原本應該履行鑰匙的職責，然後退場。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"죄인에게 죽음은 그저 도피일 뿐이라면…","JPN":"罪人にとって死がただ逃げるだけのことであるならば……","ENG":"If death is just an escape for sinners...","TWN":"如果死亡只是罪人的一種解脫……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나에게 안식은 아직 이르다.","JPN":"我はまだ死ねない。","ENG":"then it is not my time to rest yet.","TWN":"那麼我還不能安息。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 상처는… 클리파 차원을 넘어오던 타기리온과 부딪힌 흔적이겠군요.","JPN":"その傷……クリファ次元を越えようとしたタギリオンとぶつかった痕跡ですね。","ENG":"That wound... It must be a trace from fighting Thagirion crossing through the Qlipha Dimension.","TWN":"那個傷口……是穿越逆卡巴拉次元的塔基里翁留下的吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어떻게 살아 돌아온 건진 몰라도, 그런 너덜너덜한 몸뚱이로 뭘 할 수 있나요?","JPN":"どうやって生きて戻れたのかはわかりませんが、そんなボロボロな体で何ができるんですか？","ENG":"I do not know how you made it back, but what can you do with that tattered body of yours?","TWN":"雖然不知道你是怎麼活下來的，但以這副破爛不堪的身體還能做什麼？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나는 오래전, 나 자신에 대한 믿음을 잃고 추락했다.","JPN":"我は昔、自分に対する信仰を失い、地に落ちた。","ENG":"Long ago, I lost faith in myself and plummeted.","TWN":"很久以前，我失去了對自己的信仰並崩潰了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그렇게 추락한 나는 수많은 세계를 집어삼킨 타기리온의 행보를 그저 무력하게 바라볼 수밖에 없었지.","JPN":"堕落した我は、幾多の世界を飲み込んだタギリオンの動きをただ無力な状態で眺めているしかできなかった。","ENG":"Afterward, I had no choice but to watch Thagirion consume all those worlds.","TWN":"我只能無助地看著塔基里翁吞噬著無數世界。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허나, 이젠 용납하지 않으리라.","JPN":"だが、もう容赦せん。","ENG":"However, I will tolerate it no more.","TWN":"但我不會再容忍。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"더는 죄악에 파묻혀 체념하지 않겠다.","JPN":"罪悪に沈み諦めることも。","ENG":"I will no longer give into sin.","TWN":"我不會再沉溺於自己的罪孽之中。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"더는 존재하지 않는 이들에게 그건 변명일 뿐이야.","JPN":"今は存在しない者たちにとってそれは弁明に過ぎない。","ENG":"That is nothing but an excuse for those who no longer exist.","TWN":"對那些不再存在的人來說，那只是藉口而已。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"더는 복수에 눈이 멀어 방황하지 않겠다.","JPN":"復讐に血迷い我を忘れるようなことも。","ENG":"I will no longer wander, blinded by vengeance.","TWN":"我不會再被復仇蒙蔽雙眼。"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"더 일찍 그녀의 복수를 막아낼 수도 있었어.","JPN":"もっと早く彼女の復讐を止めることだってできた。","ENG":"You could have prevented her from exacting her revenge sooner.","TWN":"你本可以更早地阻止她的復仇。"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"더는 똑같은 희생이 되풀이되지 않도록.","JPN":"これ以上同じ犠牲を繰り返さないために。","ENG":"To stop the repetition of the same sacrifices.","TWN":"為了避免一遍又一遍重複著的犧牲。"},"stage":{"bg":"SWANSONG_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 잔혹한 악순환의 굴레를 이 자리에서 끊어 내리라.","JPN":"この残酷な悪循環の枷をここで断ち切る。","ENG":"This cruel, vicious cycle ends here.","TWN":"讓這個殘酷的迴圈就此打破吧——"},"stage":{"bg":"SWANSONG_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"더는 똑같은 말을 되풀이하지 마.","JPN":"もう同じ言葉を繰り返さないで。","ENG":"Don't repeat the same words again.","TWN":"不要再重複同樣的話了。"},"stage":{"bg":"SWANSONG_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"이 잔혹한 악순환의 굴레를 방관해 온건, 다름 아닌 당신이잖아.","JPN":"この残酷な悪循環の枷を傍観してきたのは、他でもなくあなたじゃない。","ENG":"It's you who has been neglecting this cruel, vicious cycle.","TWN":"一直在旁觀這個惡性循環的，不就是你嗎？！"},"stage":{"bg":"SWANSONG_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그리고 끝내는… 나의 원죄와 마주해야겠지.","JPN":"そして最後は……我の原罪と向き合うことになるのだろう。","ENG":"And in the end... I will face my original sin.","TWN":"最後……我將面對屬於我的原罪。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ONLY_CA_ARMOR_START_02"},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"윽… 뭐야? 이 광채는?","JPN":"うっ……何だ？　この光は？","ENG":"Ngh... Huh? What's that light?","TWN":"唉……這個光是什麼？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"검은 갑옷이… 사라지고 있어요.","JPN":"黒い鎧が……消えていきます。","ENG":"The black armor is... disappearing.","TWN":"黑色盔甲正在……消失。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"빛…?","JPN":"光……？","ENG":"Light...?","TWN":"這束光……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만, 이미 모든 신앙을 잃고 몰락한 그림자가… 어떻게?","JPN":"でも、すでにすべての信仰を失って落ちぶれたシャドウが……どうやって？","ENG":"But you are a fallen Shadow who lost all faith... So how?","TWN":"但是，失去所有信仰後墮落的暗影……怎麼會？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 스스로 말했잖나.","JPN":"君が自分で言ったではないか。","ENG":"You said it yourself.","TWN":"你自己不是說過嗎。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이곳은 이미 클리파 차원에 잠식되었네.","JPN":"ここは既にクリファ次元に侵食されたのだ。","ENG":"This place has already been consumed by the Qlipha Dimension.","TWN":"這個地方已經被逆卡巴拉次元侵蝕了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그 클리파의 원천은 엘리시온.","JPN":"そしてそのクリファの源はエリシオン。","ENG":"And the source of Qlipha is Elysion.","TWN":"而逆卡巴拉的源泉就是愛樂。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모르스, 그녀가 속해 있던 세계이기도 하지.","JPN":"モールス、彼女が属していた世界でもある。","ENG":"Which is the world Mors belonged to.","TWN":"也是死神曾經所在的世界。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 그녀가 가진 힘의 근간은 믿음입니다.","JPN":"しかし、彼女が持つ力の根源は信仰です。","ENG":"But her source of power is faith.","TWN":"但她的力量之根基在於信仰。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"본래의 힘을 되찾았다 하더라도, 고작 당신들 몇 명의 믿음 정도론…","JPN":"本来の力を取り戻したとしても、たかがあなたたち数人の信じる心だけでは……","ENG":"Even if she regains her strength, the handful of faith from all of you is not...","TWN":"即使恢復了能力，只憑你們幾個人……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"설마…?!","JPN":"まさか……！？","ENG":"It cannot be...!","TWN":"不……？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"온 세상의 인류가 자네가 불러들인 위협을 지켜보고 있다네.","JPN":"世界中の人類がこの脅威を見守っているのだ。","ENG":"The entire world is watching the threat you brought to their world.","TWN":"全人類都在關注你引來的威脅。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고, 지금 그 유일하게 남은 희망이 누구인지도 알고 있지.","JPN":"そして、今唯一残っている希望が誰なのかもよく知っている。","ENG":"And they know who their last hope is.","TWN":"他們應該也知道誰才是僅存的希望。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……!"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"쓸데없는 발버둥을…!","JPN":"無駄なあがきを……！","ENG":"Futile struggle...!","TWN":"無謂的掙扎……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어째서…","JPN":"どうして……","ENG":"Why...?","TWN":"為什麼……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜 아직도 그녀의 힘이 사라지지 않는 거지?","JPN":"なぜ未だに彼女の力が消えないの？","ENG":"Why are her powers not going away?","TWN":"為什麼她的力量還沒有消失？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"스완.","JPN":"スワン。","ENG":"Swan.","TWN":"史旺。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아까 제가 망원렌즈의 사용법을 모른다고 했었죠?","JPN":"さっき私に望遠レンズの使い方を知らないと言いましたよね？","ENG":"You said that I didn't know how to use the Zoom Lens, right?","TWN":"你剛才說我不會使用望遠鏡頭是嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그 말, 그대로 돌려드릴게요.","JPN":"その言葉、そのままお返しします。","ENG":"I'll say those words right back at you.","TWN":"那句話，我原封不動地還給你。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저것들은 대체…?","JPN":"あれはいったい……？","ENG":"Those are...","TWN":"那些是……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"도대체 터렛 대신 카메라만 달린 드론 수백 대를 어디다가 쓰나 했더니.","JPN":"まったく、ターレットの代わりにカメラ付きドローン数百機をどこに使うのかと思ったら。","ENG":"I was wondering where the hundreds of drones with cameras instead of turrets were going to be used.","TWN":"我還在想這數百個連炮塔都沒裝上的攝像頭無人機能有什麼用處呢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"총칼도 겁내지 않는 샤레이드 최고의 배우께서 카메라에 질색할 줄은 몰랐네. 안 그래?","JPN":"銃も刀も恐れないシャレードのトップ俳優さんがカメラを見て引くとは知らなかったよ。だろ？","ENG":"Didn't think Charade's best actress, who isn't even afraid of guns or swords, would be this frightened by cameras.","TWN":"沒想到連槍火都不懼怕的查雷德大演員會討厭攝像鏡頭喔？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…그랬었군요.","JPN":"……そうだったのですね。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"목숨이 위험한 순간에도 망원렌즈를 적극적으로 활용하지 못했던 건, 빛을 왜곡시켜 저것들을 감추기 위한 거였어요.","JPN":"命が危ない瞬間も望遠レンズを積極的に活用しなかったのは、光を歪曲させあれを隠すためでしたか。","ENG":"Even when your life was at risk, you didn't use the Zoom Lens to its full capacity... to distort the light rays and keep those things hidden.","TWN":"在危機關頭也沒有積極使用望遠鏡頭，是為了扭曲光線來隱藏它們。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"맞아요. 미치 씨에겐 미안하지만, 헬기도 드론들의 소음을 감추기 위한 위장이었죠.","JPN":"そうです。ミッチーさんには悪いけど、ヘリもドローンが出す騒音を隠すためのカモフラージュでした。","ENG":"Yup. I feel sorry for Mitchie, but even the helicopter was used to muffle the sound of the drones.","TWN":"是的，雖然有些對不起米琪小姐，其實直升機也是為了用來掩蓋無人機的噪音。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐, 그래도 관리국 스폰서 약속은 거짓말이 아니었으니까.","JPN":"ま、でも。管理局のスポンサーの約束は本当だしな。","ENG":"But still, the Administration sponsorship promise wasn't a lie.","TWN":"不過至少管理局的贊助合同是真的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신들은 모를 테죠.","JPN":"あなたたちにはわからないのです。","ENG":"You do not know.","TWN":"你們不會知道的。"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"타기리온이 거쳐간 세계가 얼마나 허무하게 무너졌는지.","JPN":"タギリオンが経てきた世界がどんなに虚しく崩れてしまったのか。","ENG":"How the worlds Thagirion passed through collapsed in vain.","TWN":"塔基里翁走過的世界是多麼徒勞地崩塌的。"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 무수한 노력에도, 내일을 빼앗기고 만 세계가 얼마나 처참했는지.","JPN":"計り知れない努力にも関わらず、明日を奪われてしまった世界の末路がどれだけ悲惨なのか。","ENG":"Despite their countless efforts, how miserable the world was after its future was taken away.","TWN":"付出無數的努力後仍然被奪走希望的世界是多麼的悲慘。"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 날을 돌려받기 위해서라면…","JPN":"その日々を返してもらうためには……","ENG":"I'll do whatever it takes...","TWN":"為了找回那一天……"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"코러스에서 모방한 파동 확산 장치, <color=#ffd34c>컨버터</color>.","JPN":"コーラスを模倣した波動拡散装置、<color=#ffd34c>コンバーター</color>。","ENG":"An imitation of Chorus' wave amplifier, <color=#ffd34c>the converter</color>.","TWN":"從Chorus模仿來的波動擴散裝置，<color=#ffd34c>轉換器</color>."},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"컨버터에 동력원을 제공해 줄 <color=#ffd34c>유사 얼터니움 리액터</color>.","JPN":"コンバーターに動力を提供する<color=#ffd34c>類似オルタニウムリアクター</color>。","ENG":"The <color=#ffd34c>pseudo-Alternium Reactor</color> provides power to the converter.","TWN":"為其提供動力的<color=#ffd34c>仿黑化永恆之金電抗器</color>."},"stage":{"bg":"ALPHA_06","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 늑대가 가진 <color=#ffd34c>클리포트 인자</color>…….","JPN":"そして、オオカミが持つ<color=#ffd34c>クリフォトファクター</color>……","ENG":"And the Wolf's <color=#ffd34c>Qliphoth Factor</color>...","TWN":"還有狼所擁有的<color=#ffd34c>逆卡巴拉因子</color>……"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"부디, 이것으로 이 무대를 끝내기 위한 <color=#ffd34c>거짓된 신</color>을……!","JPN":"どうか、これでこの舞台を終わらせるための<color=#ffd34c>偽りの神</color>を……！","ENG":"To bring the <color=#ffd34c>false god</color> to end this stage...!","TWN":"拜託了，用來結束這個舞台的<color=#ffd34c>幻神</color>……!"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"THEMA_ECCLESIA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…난 수단과 방법을 가리지 않을 겁니다.","JPN":"……私はどんな手段でも使います。","ENG":"...I will do whatever it takes.","TWN":"……我會不惜一切代價。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 저거?!","JPN":"な、なんだ？　あれ！？","ENG":"W-what's that?!","TWN":"什、什麼啊？那是什麼東西？！"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"함선에서 뭔가 엄청 거대한 게 끌려 나오고 있잖아?","JPN":"艦船から何かすごく巨大なものが出てきてるんだが？","ENG":"Something huge is being dragged out from the ship!","TWN":"艦船裡有什麼大傢伙被拽出來了？"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"스완이… 대체 뭘 불러내고 있는 거죠?","JPN":"スワンは……一体何を呼び込もうとしているのですか？","ENG":"What did... Swan summon?","TWN":"史旺她……到底在召喚什麼東西？"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"스완의 거울이 침식된 세계를 비췄군.","JPN":"スワンの鏡が侵食された世界を映したのだな。","ENG":"Swan's mirror has reflected the Corrupted world.","TWN":"史旺的鏡子照出了被侵蝕的世界。"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"클리파의 가능성을 흡수시켜 세계의 형상을 불러들인 걸세.","JPN":"クリファの可能性を吸収させ、世界の形象を呼び込んだのだ。","ENG":"It is absorbing Qilpha's possibilities to reflect the image of the world.","TWN":"它吸收了逆卡巴拉的可能性，倒映出了世界的形象。"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"멸망한 세계의 찌꺼기는 다 저런 흉물이 되는 건가?","JPN":"滅んだ世界の残骸はあんな醜いものになるの？","ENG":"Do all remnants of collapsed worlds become so hideous?","TWN":"滅亡了的世界的殘渣都會變成那種怪物？"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님은… 저런 걸 전에도 본 적이 있어?","JPN":"社長は……以前にもあんなものを見たことがある？","ENG":"Boss... Have you seen anything like this before?","TWN":"老闆……你以前見過那種東西嗎？"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네.","JPN":"ああ、そうだな。","ENG":"I have.","TWN":"是啊。"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"몇 번인지 세어보는 건 진작에 포기했지만 말이야.","JPN":"回数を数えるのはもうとっくの昔に諦めたが。","ENG":"I have stopped counting how many times after a while.","TWN":"我已經見過無數次了。"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};